using DG.Tweening;using UnityEngine;using UnityEngine.UI;namespace Game.Features.Battle.Scripts{    public sealed class HealthBarView : MonoBehaviour    {        [SerializeField] private Image _valueImage;        [SerializeField] private Image _dmgDealtImage;        [SerializeField] private float _fillTweenDuration = 0.2f;        private Tween _fillTween;        private void OnDestroy() => _fillTween?.Kill();        public void SetFillAmount(float normalized)        {            var fill = Mathf.Clamp01(normalized);            _fillTween?.Kill();            _dmgDealtImage.fillAmount = fill;            if (_fillTweenDuration <= 0f)            {                _valueImage.fillAmount = fill;                return;            }            _fillTween = _valueImage.DOFillAmount(fill, _fillTweenDuration);        }    }}